code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, icon } from 'decantr/components';

code.example:
function NamespaceBadge({ namespace }) {
  const config = {
    '@official': { variant: 'primary', icon: 'shield-check', label: '@official' },
    '@community': { variant: 'success', icon: 'users', label: '@community' }
  };
  const isOrg = namespace.startsWith('@org:');
  const cfg = isOrg
    ? { variant: 'secondary', icon: 'building', label: namespace }
    : config[namespace] || { variant: 'outline', icon: 'globe', label: namespace };

  return Badge({ variant: cfg.variant, size: 'sm' },
    icon(cfg.icon, { size: '0.75rem' }),
    ` ${cfg.label}`
  );
}

