code.example:
function NamespaceBadgeCompact({ namespace }) {
  const iconMap = { '@official': 'shield-check', '@community': 'users' };
  const variantMap = { '@official': 'primary', '@community': 'success' };
  const isOrg = namespace.startsWith('@org:');
  const ic = isOrg ? 'building' : iconMap[namespace] || 'globe';
  const variant = isOrg ? 'secondary' : variantMap[namespace] || 'outline';

  return Badge({ variant, size: 'xs', title: namespace },
    icon(ic, { size: '0.625rem' })
  );
}

