function NamespaceBadgePill({ namespace }) {
  const config = {
    '@official': { bg: '_bgprimary/15 _fgprimary', icon: 'shield-check' },
    '@community': { bg: '_bgsuccess/15 _fgsuccess', icon: 'users' }
  };
  const isOrg = namespace.startsWith('@org:');
  const cfg = isOrg
    ? { bg: '_bgsecondary/15 _fgsecondary', icon: 'building' }
    : config[namespace] || { bg: '_bgmuted/15 _fgmuted', icon: 'globe' };

  const { span } = tags;
  return span({ class: css(`_inline-flex _aic _gap1 _rfull _px3 _py1 _textsm _fontmedium ${cfg.bg}`) },
    icon(cfg.icon, { size: '0.875rem' }),
    ` ${namespace}`
  );
}

